function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;
    const dist = Array(m).fill().map(() => Array(n).fill(Infinity));
    dist[0][0] = 0;

    const dirs = [[0, 1], [1, 0]]; // right, down

    const pq = new PriorityQueue((a, b) => a[0] - b[0]);
    pq.enqueue([0, 0, 0, 0]); // [cost, row, col, remainingK]

    while (!pq.isEmpty()) {
        const [cost, row, col, remK] = pq.dequeue();

        if (row === m - 1 && col === n - 1) {
            return cost;
        }

        if (cost > dist[row][col]) continue;

        // Regular move: right or down
        for (const [dr, dc] of dirs) {
            const newRow = row + dr;
            const newCol = col + dc;
            if (newRow >= 0 && newRow < m && newCol >= 0 && newCol < n) {
                const newCost = cost + grid[newRow][newCol];
                if (newCost < dist[newRow][newCol]) {
                    dist[newRow][newCol] = newCost;
                    pq.enqueue([newCost, newRow, newCol, remK]);
                }
            }
        }

        // Teleport: find all cells with value <= current cell's value
        const currentVal = grid[row][col];
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (grid[i][j] <= currentVal && remK > 0) {
                    if (dist[i][j] > cost) {
                        dist[i][j] = cost;
                        pq.enqueue([cost, i, j, remK - 1]);
                    }
                }
            }
        }
    }

    return dist[m - 1][n - 1];
}

class PriorityQueue {
    constructor(comparator) {
        this.comparator = comparator;
        this.heap = [];
    }

    enqueue(value) {
        this.heap.push(value);
        this.heapifyUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.heap.length === 0) return null;
        const result = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.heapifyDown(0);
        return result;
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    heapifyUp(index) {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.comparator(this.heap[index], this.heap[parentIndex]) >= 0) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    heapifyDown(index) {
        const length = this.heap.length;
        while (index < length) {
            const leftChildIndex = 2 * index + 1;
            const rightChildIndex = 2 * index + 2;
            let smallerIndex = index;

            if (leftChildIndex < length && this.comparator(this.heap[leftChildIndex], this.heap[smallerIndex]) < 0) {
                smallerIndex = leftChildIndex;
            }

            if (rightChildIndex < length && this.comparator(this.heap[rightChildIndex], this.heap[smallerIndex]) < 0) {
                smallerIndex = rightChildIndex;
            }

            if (smallerIndex !== index) {
                [this.heap[index], this.heap[smallerIndex]] = [this.heap[smallerIndex], this.heap[index]];
                index = smallerIndex;
            } else {
                break;
            }
        }
    }
}

