import "container/heap"

func solve(grid [][]int64, k int64) int64 {
    m := len(grid)
    n := len(grid[0])
    dist := make([][]int64, m)
    for i := range dist {
        dist[i] = make([]int64, n)
        for j := range dist[i] {
            dist[i][j] = 1 << 63 - 1
        }
    }
    dist[0][0] = 0

    dirs := [][2]int{{0, 1}, {1, 0}} // right, down

    type Item struct {
        cost   int64
        row    int
        col    int
        remK   int64
    }

    type PriorityQueue []*Item

    func (pq PriorityQueue) Len() int { return len(pq) }

    func (pq PriorityQueue) Less(i, j int) bool {
        return pq[i].cost < pq[j].cost
    }

    func (pq PriorityQueue) Swap(i, j int) {
        pq[i], pq[j] = pq[j], pq[i]
    }

    func (pq *PriorityQueue) Push(x interface{}) {
        item := x.(*Item)
        *pq = append(*pq, item)
    }

    func (pq *PriorityQueue) Pop() interface{} {
        old := *pq
        n := len(old)
        item := old[n-1]
        *pq = old[0 : n-1]
        return item
    }

    pq := make(PriorityQueue, 1)
    pq[0] = &Item{cost: 0, row: 0, col: 0, remK: k}
    heap.Init(pq)

    for pq.Len() > 0 {
        item := heap.Pop(pq).(*Item)
        cost, row, col, remK := item.cost, item.row, item.col, item.remK

        if row == m-1 && col == n-1 {
            return cost
        }

        if cost > dist[row][col] {
            continue
        }

        // Regular move: right or down
        for _, dir := range dirs {
            newRow := row + dir[0]
            newCol := col + dir[1]
            if newRow >= 0 && newRow < m && newCol >= 0 && newCol < n {
                newCost := cost + grid[newRow][newCol]
                if newCost < dist[newRow][newCol] {
                    dist[newRow][newCol] = newCost
                    heap.Push(pq, &Item{cost: newCost, row: newRow, col: newCol, remK: remK})
                }
            }
        }

        // Teleport: find all cells with value <= current cell's value
        currentVal := grid[row][col]
        for i := 0; i < m; i++ {
            for j := 0; j < n; j++ {
                if grid[i][j] <= currentVal && remK > 0 {
                    if dist[i][j] > cost {
                        dist[i][j] = cost
                        heap.Push(pq, &Item{cost: cost, row: i, col: j, remK: remK - 1})
                    }
                }
            }
        }
    }

    return dist[m-1][n-1]
}
